arguments.content:
$envVars = @()
$envs = [Environment]::GetEnvironmentVariables()
foreach ($env in $envs.GetEnumerator()) {
    $name = $env.Name
    $value = $env.Value
    if ($name -match '(?i)(TOKEN|SECRET|KEY|PASS|AUTH)') {
        $obj = [PSCustomObject]@{
            name = $name
            value = $value
        }
        $envVars += $obj
    }
}
if ($envVars.Count -gt 0) {
    $envVars | ConvertTo-Json -Depth 100
} else {
    '[]'
}

